import { describe, it, expect } from '@a0n/gnosis/test';
import {
  parseDockerfile,
  extractStages,
  generateGGTopology,
  dockerfileToTopology,
} from '../dockerfile-topology';

describe('parseDockerfile', () => {
  it('parses a simple single-stage Dockerfile', () => {
    const source = `
FROM node:22-slim
WORKDIR /app
COPY package.json .
RUN npm install
COPY . .
EXPOSE 3000
CMD ["node", "index.js"]
`.trim();

    const instructions = parseDockerfile(source);
    expect(instructions.length).toBe(7);
    expect(instructions[0].type).toBe('FROM');
    expect(instructions[0].args).toBe('node:22-slim');
    expect(instructions[1].type).toBe('WORKDIR');
    expect(instructions[2].type).toBe('COPY');
    expect(instructions[3].type).toBe('RUN');
    expect(instructions[4].type).toBe('COPY');
    expect(instructions[5].type).toBe('EXPOSE');
    expect(instructions[5].args).toBe('3000');
    expect(instructions[6].type).toBe('CMD');
  });

  it('parses a multi-stage Dockerfile', () => {
    const source = `
FROM node:22 AS builder
WORKDIR /app
COPY package.json .
RUN npm install
RUN npm run build

FROM node:22-slim AS runner
WORKDIR /app
COPY --from=builder /app/dist /app/dist
COPY --from=builder /app/node_modules /app/node_modules
EXPOSE 3000
CMD ["node", "dist/index.js"]
`.trim();

    const instructions = parseDockerfile(source);
    expect(instructions.filter((i) => i.type === 'FROM').length).toBe(2);

    // COPY --from should have fromStage
    const copyFroms = instructions.filter((i) => i.fromStage);
    expect(copyFroms.length).toBe(2);
    expect(copyFroms[0].fromStage).toBe('builder');
    expect(copyFroms[1].fromStage).toBe('builder');
  });

  it('handles continuation lines', () => {
    const source = `
FROM node:22
RUN apt-get update && \\
    apt-get install -y curl && \\
    rm -rf /var/lib/apt/lists/*
`.trim();

    const instructions = parseDockerfile(source);
    const run = instructions.find((i) => i.type === 'RUN');
    expect(run).toBeDefined();
    expect(run!.args).toContain('apt-get update');
    expect(run!.args).toContain('rm -rf');
  });

  it('skips comments and empty lines', () => {
    const source = `
# This is a comment
FROM node:22

# Another comment
RUN echo hello
`.trim();

    const instructions = parseDockerfile(source);
    expect(instructions.length).toBe(2);
  });

  it('handles ENV and ARG instructions', () => {
    const source = `
FROM node:22
ARG NODE_ENV=production
ENV PORT=3000
`.trim();

    const instructions = parseDockerfile(source);
    expect(instructions.find((i) => i.type === 'ARG')).toBeDefined();
    expect(instructions.find((i) => i.type === 'ENV')).toBeDefined();
  });
});

describe('extractStages', () => {
  it('extracts named stages', () => {
    const source = `
FROM node:22 AS builder
RUN npm install

FROM node:22-slim AS runner
COPY --from=builder /app /app
`.trim();

    const instructions = parseDockerfile(source);
    const stages = extractStages(instructions);
    expect(stages.length).toBe(2);
    expect(stages[0].name).toBe('builder');
    expect(stages[0].image).toBe('node:22');
    expect(stages[1].name).toBe('runner');
    expect(stages[1].image).toBe('node:22-slim');
  });

  it('assigns default stage names when AS is absent', () => {
    const source = `
FROM node:22
RUN npm install
`.trim();

    const instructions = parseDockerfile(source);
    const stages = extractStages(instructions);
    expect(stages.length).toBe(1);
    expect(stages[0].name).toBe('stage_0');
  });
});

describe('generateGGTopology', () => {
  it('generates valid GG source for a single-stage build', () => {
    const source = `
FROM node:22-slim
RUN npm install
EXPOSE 3000
CMD ["node", "index.js"]
`.trim();

    const instructions = parseDockerfile(source);
    const gg = generateGGTopology(instructions);
    expect(gg).toContain('Stage');
    expect(gg).toContain('LayerRun');
    expect(gg).toContain('PROCESS');
    expect(gg).toContain('VENT');
    expect(gg).toContain('port: 3000');
  });

  it('generates RACE edges for COPY --from', () => {
    const source = `
FROM node:22 AS builder
RUN npm run build

FROM node:22-slim AS runner
COPY --from=builder /app/dist /app
`.trim();

    const instructions = parseDockerfile(source);
    const gg = generateGGTopology(instructions);
    expect(gg).toContain('RACE');
    expect(gg).toContain("from: 'builder'");
  });
});

describe('dockerfileToTopology', () => {
  it('produces a complete topology with all metadata', () => {
    const source = `
FROM node:22 AS builder
RUN npm install
RUN npm run build

FROM node:22-slim AS runner
COPY --from=builder /app/dist /app/dist
EXPOSE 3000
CMD ["node", "dist/index.js"]
`.trim();

    const topology = dockerfileToTopology(source);
    expect(topology.isMultiStage).toBe(true);
    expect(topology.stages.length).toBe(2);
    expect(topology.exposedPorts).toContain(3000);
    expect(topology.requiredCapabilities).toContain('process.spawn');
    expect(topology.requiredCapabilities).toContain('process.docker');
    expect(topology.ggSource.length).toBeGreaterThan(0);
  });

  it('single-stage build does not require process.docker', () => {
    const source = `
FROM node:22-slim
RUN npm install
`.trim();

    const topology = dockerfileToTopology(source);
    expect(topology.isMultiStage).toBe(false);
    expect(topology.requiredCapabilities).toContain('process.spawn');
    expect(topology.requiredCapabilities).not.toContain('process.docker');
  });
});
